12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	interface QuoteResult {
17	  premium: number;
18	}
19	
20	interface ClaimResult {
21	  payout: number;
22	  remainingCap: number;
23	}
24	
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PRICE = 60;
27	
28	interface Item {
29	  type: string;
30	  material?: string;
31	  enchantment?: number;
32	  cursed?: boolean;
33	}
34	
35	interface Damage {
36	  itemType: string;
37	  amount: number;
38	}
39	
40	interface Incident {
41	  cause: string;
42	  damages: Array<Damage>;
43	}
44	
45	interface QuoteStep {
46	  op: "quote";
47	  items: Array<Item>;
48	}
49	
50	interface ClaimStep {
51	  op: "claim";
52	  policy: number;
53	  incident: Incident;
54	}
55	
56	type Step = QuoteStep | ClaimStep;
57	
58	const CURSED_SURCHARGE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_THRESHOLD = 5;
60	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
61	const FIRST_INSURANCE_RATE = 0.1;
62	const LOYALTY_THRESHOLD = 2;
63	const LOYALTY_DISCOUNT_RATE = 0.2;
64	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
65	
66	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
67	
68	const itemSurcharge = (item: Item): number => {
69	  const base = basePremiumFor(item.type);
70	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
71	  const enchantmentSurcharge =
72	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
73	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
74	      : 0;
75	  return cursedSurcharge + enchantmentSurcharge;
76	};
77	
78	const countByType = (items: Array<Item>): Record<string, number> => {
79	  const counts: Record<string, number> = {};
80	  for (const item of items) {
81	    counts[item.type] = (counts[item.type] ?? 0) + 1;
82	  }
83	  return counts;
84	};
85	
86	const policyBasePremiumFor = (items: Array<Item>): number => {
87	  const typeCounts = countByType(items);
88	  return Object.entries(typeCounts).reduce(
89	    (total, [type, count]) =>
90	      total + (count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * basePremiumFor(type)),
91	    0,
92	  );
93	};
94	
95	const quotePremium = (customer: Customer, items: Array<Item>, quoteIndex: number): number => {
96	  const policyBasePremium = policyBasePremiumFor(items);
97	  const totalSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
98	  const firstInsurance = policyBasePremium * FIRST_INSURANCE_RATE;
99	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD
100	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
101	    : 0;
102	  const followUpDiscount = quoteIndex > 0
103	    ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE
104	    : 0;
105	  const grossPremium = policyBasePremium + totalSurcharges + firstInsurance;
106	  const totalDiscounts = loyaltyDiscount + followUpDiscount;
107	  return Math.ceil(grossPremium - totalDiscounts + PROCESSING_FEE);
108	};
109	
110	const INSURANCE_VALUE_MULTIPLIER = 10;
111	
112	const DEDUCTIBLE = 100;
113	const CAP_MULTIPLIER = 2;
114	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
115	const CLAIM_HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
116	
117	const insuranceSumFor = (policyItems: Array<Item>): number =>
118	  policyItems.reduce(
119	    (sum, item) => sum + basePremiumFor(item.type) * INSURANCE_VALUE_MULTIPLIER,
120	    0,
121	  );
122	
123	const validateDamages = (damages: Array<Damage>): void => {
124	  for (const damage of damages) {
125	    if (damage.amount < 0) {
126	      throw new Error("Damage amount cannot be negative");
127	    }
128	  }
129	};
130	
131	const findPolicyItem = (policyItems: Array<Item>, itemType: string): Item => {
132	  const matchingItem = policyItems.find((item) => item.type === itemType);
133	  if (!matchingItem) {
134	    throw new Error(`Item type "${itemType}" not found in policy`);
135	  }
136	  return matchingItem;
137	};
138	
139	const reimbursablePayoutFor = (damage: Damage, policyItems: Array<Item>): number => {
140	  const matchingItem = findPolicyItem(policyItems, damage.itemType);
141	  const enchantment = matchingItem.enchantment ?? 0;
142	  const reimbursableAmount = enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD
143	    ? damage.amount * CLAIM_HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
144	    : damage.amount;
145	  return Math.max(0, reimbursableAmount - DEDUCTIBLE);
146	};
147	
148	const validateDamageCountsAgainstPolicy = (
149	  damages: Array<Damage>,
150	  policyItems: Array<Item>,
151	): void => {
152	  const damageCounts: Record<string, number> = {};
153	  for (const damage of damages) {
154	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
155	  }
156	  const policyCounts = countByType(policyItems);
157	  for (const [type, count] of Object.entries(damageCounts)) {
158	    if (count > (policyCounts[type] ?? 0)) {
159	      throw new Error(`More damage entries for "${type}" than policy covers`);
160	    }
161	  }
162	};
163	
164	const processClaim = (
165	  policyItems: Array<Item>,
166	  remainingCap: number,
167	  damages: Array<Damage>,
168	): ClaimResult => {
169	  validateDamages(damages);
170	  validateDamageCountsAgainstPolicy(damages, policyItems);
171	  const totalPayout = damages.reduce(
172	    (sum, damage) => sum + reimbursablePayoutFor(damage, policyItems),
173	    0,
174	  );
175	  const cappedPayout = Math.min(totalPayout, remainingCap);
176	  return {
177	    payout: Math.floor(cappedPayout),
178	    remainingCap: remainingCap - cappedPayout,
179	  };
180	};
181	
182	export const processSteps = (customer: Customer, steps: Array<Step>): Array<QuoteResult | ClaimResult> => {
183	  const policies: Array<Array<Item>> = [];
184	  const policyCaps: Map<number, number> = new Map();
185	  return steps.map((step) => {
186	    if (step.op === "claim") {
187	      const remainingCap = policyCaps.get(step.policy) ?? CAP_MULTIPLIER * insuranceSumFor(policies[step.policy]);
188	      const result = processClaim(policies[step.policy], remainingCap, step.incident.damages);
189	      policyCaps.set(step.policy, result.remainingCap);
190	      return result;
191	    }
192	    const result = {
193	      premium: quotePremium(customer, step.items, policies.length),
194	    };
195	    policies.push(step.items);
196	    return result;
197	  });
198	};
