56	type Step = QuoteStep | ClaimStep;
57	
58	const CURSED_SURCHARGE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_THRESHOLD = 5;
60	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
61	const FIRST_INSURANCE_RATE = 0.1;
62	const LOYALTY_THRESHOLD = 2;
63	const LOYALTY_DISCOUNT_RATE = 0.2;
64	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
65	
66	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
67	
68	const itemSurcharge = (item: Item): number => {
69	  const base = basePremiumFor(item.type);
70	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
71	  const enchantmentSurcharge =
72	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
73	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
74	      : 0;
75	  return cursedSurcharge + enchantmentSurcharge;
76	};
77	
78	const countBy = <T>(items: Array<T>, keyOf: (item: T) => string): Record<string, number> => {
79	  const counts: Record<string, number> = {};
80	  for (const item of items) {
81	    const key = keyOf(item);
82	    counts[key] = (counts[key] ?? 0) + 1;
83	  }
84	  return counts;
85	};
86	
87	const countByType = (items: Array<Item>): Record<string, number> =>
88	  countBy(items, (item) => item.type);
89	
90	const policyBasePremiumFor = (items: Array<Item>): number => {
91	  const typeCounts = countByType(items);
92	  return Object.entries(typeCounts).reduce(
93	    (total, [type, count]) =>
94	      total + (count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * basePremiumFor(type)),
95	    0,
96	  );
97	};
98	
99	const quotePremium = (customer: Customer, items: Array<Item>, quoteIndex: number): number => {
100	  const policyBasePremium = policyBasePremiumFor(items);
101	  const totalSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
102	  const firstInsurance = policyBasePremium * FIRST_INSURANCE_RATE;
103	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD
104	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
105	    : 0;
106	  const followUpDiscount = quoteIndex > 0
107	    ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE
108	    : 0;
109	  const grossPremium = policyBasePremium + totalSurcharges + firstInsurance;
110	  const totalDiscounts = loyaltyDiscount + followUpDiscount;
111	  return Math.ceil(grossPremium - totalDiscounts + PROCESSING_FEE);
112	};
113	
114	const INSURANCE_VALUE_MULTIPLIER = 10;
115	
116	const DEDUCTIBLE = 100;
117	const CAP_MULTIPLIER = 2;
118	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
119	const CLAIM_HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
120	
121	const insuranceSumFor = (policyItems: Array<Item>): number =>
122	  policyItems.reduce(
123	    (sum, item) => sum + basePremiumFor(item.type) * INSURANCE_VALUE_MULTIPLIER,
124	    0,
125	  );
