135	const findPolicyItem = (policyItems: Array<Item>, itemType: string): Item => {
136	  const matchingItem = policyItems.find((item) => item.type === itemType);
137	  if (!matchingItem) {
138	    throw new Error(`Item type "${itemType}" not found in policy`);
139	  }
140	  return matchingItem;
141	};
142	
143	const reimbursablePayoutFor = (damage: Damage, policyItems: Array<Item>): number => {
144	  const matchingItem = findPolicyItem(policyItems, damage.itemType);
145	  const enchantment = matchingItem.enchantment ?? 0;
146	  const reimbursableAmount = enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD
147	    ? damage.amount * CLAIM_HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
148	    : damage.amount;
149	  return Math.max(0, reimbursableAmount - DEDUCTIBLE);
150	};
151	
152	const validateDamageCountsAgainstPolicy = (
153	  damages: Array<Damage>,
154	  policyItems: Array<Item>,
155	): void => {
156	  const damageCounts = countBy(damages, (d) => d.itemType);
157	  const policyCounts = countByType(policyItems);
158	  for (const [type, count] of Object.entries(damageCounts)) {
159	    if (count > (policyCounts[type] ?? 0)) {
