165	const processClaim = (
166	  policyItems: Array<Item>,
167	  remainingCap: number,
168	  damages: Array<Damage>,
169	): ClaimResult => {
170	  validateDamages(damages);
171	  validateDamageCountsAgainstPolicy(damages, policyItems);
172	  const totalPayout = damages.reduce(
173	    (sum, damage) => sum + reimbursablePayoutFor(damage, policyItems),
174	    0,
175	  );
176	  const cappedPayout = Math.min(totalPayout, remainingCap);
177	  return {
178	    payout: Math.floor(cappedPayout),
179	    remainingCap: remainingCap - cappedPayout,
180	  };
181	};
