183	export const processSteps = (customer: Customer, steps: Array<Step>): Array<QuoteResult | ClaimResult> => {
184	  const policies: Array<Array<Item>> = [];
185	  const policyCaps: Map<number, number> = new Map();
186	  return steps.map((step) => {
187	    if (step.op === "claim") {
188	      const remainingCap = policyCaps.get(step.policy) ?? CAP_MULTIPLIER * insuranceSumFor(policies[step.policy]);
189	      const result = processClaim(policies[step.policy], remainingCap, step.incident.damages);
190	      policyCaps.set(step.policy, result.remainingCap);
191	      return result;
192	    }
193	    const result = {
194	      premium: quotePremium(customer, step.items, policies.length),
195	    };
196	    policies.push(step.items);
